{
  "steps": [
    {
      "step_id": "cb_step_1",
      "title": "Select CT Volume",
      "simple": "Select the CT scan of the shoulder to use for bone density analysis.",
      "detailed": "This scan will be used to assess bone density and create a 3D model of the bone. Choose the appropriate CT volume from the dropdown list in the module's first section."
    },
    {
      "step_id": "cb_step_2",
      "title": "Create Bone Segmentation",
      "simple": "Switch to the Segment Editor module and create a new segmentation named 'Bone_Segmentation'.",
      "detailed": "Segmentation isolates the bone from surrounding tissues, which is necessary for accurate 3D reconstruction and screw path planning. Use the Segment Editor to create this segmentation."
    },
    {
      "step_id": "cb_step_3",
      "title": "Add Bone Segment",
      "simple": "Click the 'Add' button in the Segment Editor and rename the new segment to 'Bone_Segment'.",
      "detailed": "This segment will hold the bone density threshold segmentation. Naming it clearly helps keep the scene organized."
    },
    {
      "step_id": "cb_step_4",
      "title": "Open Threshold",
      "simple": "Click the 'Threshold' button in the Segment Editor toolbar.",
      "detailed": "Thresholding selects pixels within a certain density range, making it possible to isolate bone from soft tissue. This opens the threshold effect panel."
    },
    {
      "step_id": "cb_step_5",
      "title": "Set Threshold Range",
      "simple": "Adjust the threshold slider to select the bone density range appropriate for your CT scan.",
      "detailed": "Bone has a characteristic density (in Hounsfield units) that differs from soft tissue. Set the lower and upper limits to capture the bone while excluding air and muscle. The segmentation preview will update in real time."
    },
    {
      "step_id": "cb_step_6",
      "title": "Apply Threshold",
      "simple": "Click the 'Apply' button to run the threshold segmentation.",
      "detailed": "This creates a binary mask of the bone based on your selected density range. You will see the bone highlighted in the segmentation overlay."
    },
    {
      "step_id": "cb_step_7",
      "title": "Open Islands Effect",
      "simple": "Click the 'Islands' button in the Segment Editor.",
      "detailed": "The threshold may include small disconnected regions (islands) from noise. The Islands effect allows you to remove these and keep only the main bone structure."
    },
    {
      "step_id": "cb_step_8",
      "title": "Keep Largest Island",
      "simple": "Select the 'Keep largest island' option.",
      "detailed": "This will discard all smaller disconnected regions, leaving only the main bone (e.g., the scapula and humeral head). This cleans up the segmentation."
    },
    {
      "step_id": "cb_step_9",
      "title": "Apply Islands",
      "simple": "Click the 'Apply' button to finalize the island removal.",
      "detailed": "The segmentation now contains only the largest connected bone region, which will be used for 3D reconstruction."
    },
    {
      "step_id": "cb_step_10",
      "title": "Select Bone Segment",
      "simple": "Select the bone segment you just created from the scene.",
      "detailed": "This identifies the segment to be used for 3D reconstruction. Choose 'Bone_Segment' from the list."
    },
    {
      "step_id": "cb_step_11",
      "title": "3D Reconstruction",
      "simple": "Click the '3D Reconstruction' button to generate a 3D model from the bone segmentation.",
      "detailed": "This creates a surface model of the bone that will be used for planning the prosthesis placement and screw trajectories."
    },
    {
      "step_id": "cb_step_12",
      "title": "Adjust View for Fiducial Placement",
      "simple": "Rotate and zoom the 3D view to get a clear angle of the glenoid cavity surface.",
      "detailed": "A good view of the glenoid (the socket of the shoulder) is essential for accurately placing the prosthesis center point. Position the camera so the glenoid surface is clearly visible and easy to click when you reach the placement step."
    },
    {
      "step_id": "cb_step_13",
      "title": "Create Prosthesis Center Point",
      "simple": "Switch to the Markups module, click 'Point List', and create a new fiducial node named 'Prosthesis_center_point'.",
      "detailed": "This point marks the center of the glenoid where the prosthesis will be positioned. Creating it now prepares the fiducial for precise placement in the next step."
    },
    {
      "step_id": "cb_step_14",
      "title": "Place Prosthesis Center Point",
      "simple": "Click on the glenoid cavity surface to place a single fiducial point.",
      "detailed": "Place the point exactly at the intended center of the glenoid cavity — this will be used to align the prosthesis. Ensure it is positioned accurately before clicking Done."
    },
    {
      "step_id": "cb_step_15",
      "title": "Select Planning Point",
      "simple": "Select the MarkupsFiducial node you just created ('Prosthesis_center_point').",
      "detailed": "This tells the module which point to use as the prosthesis center. Choose it from the dropdown list in the 'Planning point' section."
    },
    {
      "step_id": "cb_step_16",
      "title": "Prosthesis Implantation",
      "simple": "Click the 'Prosthesis implantation' button to generate the prosthesis based on the center point.",
      "detailed": "The module will create a 3D model of the prosthesis and position it at the marked glenoid center. This is a key step in planning the surgery."
    },
    {
      "step_id": "cb_step_17",
      "title": "Adjust Prosthesis?",
      "simple": "If you need to adjust the position of the prosthesis, check the 'Adjust Prosthesis (3D transform handles)' box. Otherwise, click Done to continue.",
      "detailed": "You can fine-tune the prosthesis placement using interactive 3D handles. If the initial position looks good, skip to the next step."
    },
    {
      "step_id": "cb_step_18",
      "title": "Adjust View for Prosthesis",
      "simple": "Rotate and zoom the 3D view to inspect the prosthesis placement from all angles.",
      "detailed": "Check that the prosthesis is correctly aligned with the glenoid surface and the planned screw paths. A thorough visual inspection helps ensure good fit."
    },
    {
      "step_id": "cb_step_19",
      "title": "Update Prosthesis",
      "simple": "Click the 'Update Prosthesis' button to apply any changes after manual adjustment.",
      "detailed": "This recalculates the prosthesis position based on your modifications. The model will update in the 3D view."
    },
    {
      "step_id": "cb_step_20",
      "title": "Generate Screw Plan",
      "simple": "Click the 'Plan' button to generate the screw plan.",
      "detailed": "This calculates optimal screw trajectories for securing the prosthesis to the bone. The plan will be shown as lines in the 3D view."
    },
    {
      "step_id": "cb_step_21",
      "title": "Adjust Screw?",
      "simple": "If you need to modify the screw paths, check the 'Adjust screw' box. Otherwise, click Done to finish.",
      "detailed": "You can adjust the endpoints of the planning paths to improve screw placement. If the plan is satisfactory, you are done."
    },
    {
      "step_id": "cb_step_22",
      "title": "Adjust View for Screw Paths",
      "simple": "Rotate and zoom the 3D view to clearly see the screw planning paths.",
      "detailed": "A clear view of the screw trajectories is needed to evaluate their positions relative to the bone and prosthesis. Use the view controls to inspect from multiple angles."
    },
    {
      "step_id": "cb_step_23",
      "title": "Update Screw",
      "simple": "Click the 'Update screw' button to finalize any screw path adjustments.",
      "detailed": "This applies your changes and updates the screw plan. The final screw trajectories are now ready for surgical reference."
    }
  ]
}
